import { useState, useContext } from "react";
import { ThemeProvider, ThemeContext } from "./context/ThemeContext";
import Sidebar from "./components/Sidebar";
import TopBar from "./components/TopBar";
import ChatArea from "./components/ChatArea";

export default function App() {
    const [chats, setChats] = useState([
        { id: Date.now(), title: "New chat", messages: [] }
    ]);
    const [activeChatId, setActiveChatId] = useState(chats[0].id);
    const [isStreaming, setIsStreaming] = useState(false);

    const activeChat = chats.find(c => c.id === activeChatId);

    // New chat
    const newChat = () => {
        const chat = { id: Date.now(), title: "New chat", messages: [] };
        setChats([chat, ...chats]);
        setActiveChatId(chat.id);
    };

    // Rename chat
    const renameChat = (id, newTitle) => {
        setChats(prev =>
            prev.map(chat =>
                chat.id === id ? { ...chat, title: newTitle } : chat
            )
        );
    };

    // Delete chat
    const deleteChat = (id) => {
        setChats(prev => {
            const updated = prev.filter(chat => chat.id !== id);

            if (updated.length === 0) {
                const newChat = {
                    id: Date.now(),
                    title: "New chat",
                    messages: []
                };
                setActiveChatId(newChat.id);
                return [newChat];
            }

            if (id === activeChatId) {
                setActiveChatId(updated[0].id);
            }

            return updated;
        });
    };

    // Add user message
    const addUserMessage = (text) => {
        setChats(prev =>
            prev.map(chat =>
                chat.id === activeChatId
                    ? {
                        ...chat,
                        title:
                            chat.messages.length === 0
                                ? text.slice(0, 30)
                                : chat.title,
                        messages: [...chat.messages, { role: "user", text }]
                    }
                    : chat
            )
        );
    };

    // Stream AI response
    const streamAIResponse = async (text) => {
        setIsStreaming(true);

        setChats(prev =>
            prev.map(chat =>
                chat.id === activeChatId
                    ? {
                        ...chat,
                        messages: [...chat.messages, { role: "ai", text: "" }]
                    }
                    : chat
            )
        );

        const res = await fetch("http://127.0.0.1:8000/api/chat", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ message: text })
        });

        const reader = res.body.getReader();
        const decoder = new TextDecoder();
        let aiText = "";

        while (true) {
            const { value, done } = await reader.read();
            if (done) break;

            aiText += decoder.decode(value);
            setChats(prev =>
                prev.map(chat =>
                    chat.id === activeChatId
                        ? {
                            ...chat,
                            messages: chat.messages.map((m, i) =>
                                i === chat.messages.length - 1
                                    ? { ...m, text: aiText }
                                    : m
                            )
                        }
                        : chat
                )
            );
        }

        setIsStreaming(false);
    };

    return (
        <ThemeProvider>
            <ThemedAppWrapper>
                <Sidebar
                    chats={chats}
                    activeChatId={activeChatId}
                    onNewChat={newChat}
                    onSelectChat={setActiveChatId}
                    onRenameChat={renameChat}
                    onDeleteChat={deleteChat}
                />

                <div className="main-wrapper">
                    <TopBar />
                    <ChatArea
                        chat={activeChat}
                        onSend={addUserMessage}
                        onStream={streamAIResponse}
                        isStreaming={isStreaming}
                    />
                </div>
            </ThemedAppWrapper>
        </ThemeProvider>
    );
}

function ThemedAppWrapper({ children }) {
    const { theme } = useContext(ThemeContext);
    return <div className={`app ${theme}`}>{children}</div>;
}
